mapper.select:
SELECT *
FROM bank_country
WHERE tenant_id = #{tenantId}
  AND code = #{code}
LIMIT 1

SELECT *
FROM bank_option
WHERE tenant_id = #{tenantId}
  AND country_id = #{countryId}
  AND name = #{name}
LIMIT 1

SELECT *
FROM bank_country
WHERE tenant_id = #{tenantId}
  AND id = #{id}
LIMIT 1

SELECT *
FROM bank_option
WHERE tenant_id = #{tenantId}
  AND country_id = #{countryId}
  AND id = #{id}
LIMIT 1

SELECT *
FROM bank_option
WHERE tenant_id = #{tenantId}
  AND country_id = #{countryId}
ORDER BY name ASC

mapper.delete:
DELETE FROM bank_country
WHERE tenant_id = #{tenantId}
  AND id = #{id}

DELETE FROM bank_option
WHERE tenant_id = #{tenantId}
  AND id = #{id}
  AND country_id = #{countryId}
